pub async fn get_events_between(pool: &sqlx::PgPool, start: &chrono::DateTime<chrono::Utc>, end: &chrono::DateTime<chrono::Utc>) -> Result<Vec<GetEventsBetweenRow>, sqlx::Error> {
    sqlx::query_as!(GetEventsBetweenRow, "SELECT id, name, created_at FROM events WHERE created_at BETWEEN $1 AND $2", start, end)
        .fetch_all(pool)
        .await
}

